if (!function_exists('prod_t')) {
  function prod_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('prod_h')) {
  function prod_h($key, $fallback = '') { return htmlspecialchars((string) prod_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('prod_js')) {
  function prod_js($key, $fallback = '') { return json_encode(prod_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
$defaultFrom=date('Y-m-d',strtotime('-7 days'));$defaultTo=date('Y-m-d',strtotime('+14 days'));
$plants=$db->query("SELECT DISTINCT plant AS plant_code FROM production_order WHERE plant IS NOT NULL AND plant<>'' UNION SELECT DISTINCT plant_code FROM erp_production_schedule WHERE plant_code IS NOT NULL AND plant_code<>'' ORDER BY plant_code");
$workCenters=$db->query("SELECT DISTINCT work_center FROM production_order_operation WHERE work_center IS NOT NULL AND work_center<>'' UNION SELECT DISTINCT work_center FROM erp_production_schedule_detail WHERE work_center IS NOT NULL AND work_center<>'' ORDER BY work_center");
$shifts=$db->query("SELECT DISTINCT shift_code FROM erp_production_schedule_detail WHERE shift_code IS NOT NULL AND shift_code<>'' UNION SELECT kode_shift FROM erp_shift WHERE status='Aktif' ORDER BY shift_code");
$kpi=$db->fetch("SELECT COUNT(*) op_count,SUM(o.status='OPEN') open_count,SUM(o.status='STARTED') started_count,SUM(o.status='FINISHED') finished_count FROM production_order_operation o JOIN production_order p ON p.id_production_order=o.id_production_order WHERE p.status IN ('RELEASED','IN_PROCESS','CONFIRMED') AND p.start_date BETWEEN ? AND ?",array($defaultFrom,$defaultTo));
?>
