><label class="control-label col-lg-1"><?=prod_h('production_shift', 'Shift');?></label><div class="col-lg-2"><select id="filter_shift" class="form-control"><option value=""><?=prod_h('common_all', 'All');?></option><?php foreach($shifts as $s){ ?><option value="<?=htmlspecialchars($s->shift_code,ENT_QUOTES,'UTF-8');?>"><?=htmlspecialchars($s->shift_code,ENT_QUOTES,'UTF-8');?></option><?php } ?></select></div><label class="control-label col-lg-1">Readiness</label><div class="col-lg-2"><select id="filter_readiness" class="form-control"><option value=""><?=prod_h('common_all', 'All');?></option><option value="READY">Material Ready</option><option value="SHORTAGE">Material Shortage</option><option value="DOWNTIME">Has Downtime</option></select></div><div class="col-lg-2"><input id="filter_keyword" class="form-control" placeholder="PO, material, operation"></div></div><div class="form-group"><div class="col-lg-offset-2 col-lg-10"><button id="btn_filter_oq" class="btn btn-primary"><i class="fa fa-filter"></i> <?=prod_h('common_filter', 'Filter');?></button> <button id="btn_reset_oq" class="btn btn-default"><i class="fa fa-refresh"></i> <?=prod_h('common_reset', 'Reset');?></button> <button id="btn_excel_oq" class="btn btn-success"><i class="fa fa-file-excel-o"></i> <?=prod_h('common_export_excel', 'Export Excel');?></button></div></div></form></div></div>
