<script>
function oqError(m){$('.isi_warning_delete').text(m||<?=prod_js('production_operation_queue_process_failed', 'Operation Queue failed to process.');?>);$('.error_data_delete').fadeIn();}
function oqFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),plant:$('#filter_plant').val(),operation_status:$('#filter_operation_status').val(),work_center:$('#filter_work_center').val(),shift:$('#filter_shift').val(),readiness:$('#filter_readiness').val(),keyword:$('#filter_keyword').val()};}
function oqQuery(){return $.param(oqFilters());}
$(function(){if($.fn.datepicker){$('.oq-date').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_plant,#filter_operation_status,#filter_work_center,#filter_shift,#filter_readiness').select2({width:'100%',allowClear:true});}
var dt=$('#dtb_operation_queue').DataTable({bProcessing:true,bServerSide:true,pageLength:25,ordering:false,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=prod_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'38px',targets:0},{width:'100px',targets:1},{className:'oq-progress',targets:9}],ajax:{url:'<?=base_admin();?>modul/operation_queue/operation_queue_data.php',type:'post',data:function(d){$.extend(d,oqFilters());},error:function(xhr){console.log(xhr.responseText);oqError(<?=prod_js('production_operation_queue_load_failed', 'Operation Queue data failed to load.');?>);}}});
$('#btn_filter_oq').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_oq').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_plant,#filter_operation_status,#filter_work_center,#filter_shift,#filter_readiness').val('').trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_excel_oq').click(function(){window.location='<?=base_admin();?>modul/operation_queue/operation_queue_action.php?act=excel&'+oqQuery();});
$(document).on('click','.btn-oq-detail',function(){$.post('<?=base_admin();?>modul/operation_queue/operation_queue_action.php?act=detail',{id:$(this).data('id'),source_type:$(this).data('source')},function(html){$('#oq_detail_body').html(html);$('#modal_detail_oq').modal('show');}).fail(function(){oqError('Detail gagal dibuka.');});});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});
});
</script>
